function fb = csirs_feedback(carrier, csirs, H_est_full, nVar_all, slotAssign)
%CSIRS_FEEDBACK  CSI feedback (RI/PMI/CQI/Cap) for Approaches B, C, D.
%
%  Approach B: Full 128-port SVD upper bound (ideal reference)
%  Approach C: Rel-19 Type I Single-Panel Mode A (TS 38.214 S5.2.2.2.1a)
%  Approach D: Rel-19 Type I Single-Panel Mode B (TS 38.214 S5.2.2.2.1a)
%
%  CQI is computed via nr5g.internal.nrCQISelect which uses L2SM (MIESM)
%  internally — BLER threshold 10% per TS 38.214 S5.2.2.1.
%
%  Inputs:
%    carrier      - nrCarrierConfig
%    csirs        - {1x4} nrCSIRSConfig objects (csirs{1} used for C/D)
%    H_est_full   - [K x 28 x nRx x 128] estimated channel
%    nVar_all     - [1x4] noise variance per resource
%    slotAssign   - [1x4] slot index per resource
%
%  Output:
%    fb - struct:
%           .ri_B,  .cqi_B,  .cap_B,  .W_B,  .sinrPerRE_B
%           .ri_C,  .cqi_C,  .cap_C,  .W_C,  .sinrPerRE_C
%           .ri_D,  .cqi_D,  .cap_D,  .W_D,  .sinrPerRE_D
%         cqi_* is wideband scalar; cap_* is scalar (bits/s/Hz)

nRxAntennas  = size(H_est_full, 3);
nTxAntennas  = size(H_est_full, 4);
nPortsPerRes = nTxAntennas / 4;
nSymPerSlot  = carrier.SymbolsPerSlot;

% ── Wideband channel matrix H_wb [nRx x nTx] ─────────────────────────────
H_wb = zeros(nRxAntennas, nTxAntennas);
for r = 1:4
    pS = (r-1)*nPortsPerRes + 1;  pE = r*nPortsPerRes;
    sS = slotAssign(r)*nSymPerSlot + 1;
    sE = (slotAssign(r)+1)*nSymPerSlot;
    H_wb(:, pS:pE) = squeeze(mean(H_est_full(:, sS:sE, :, pS:pE), [1 2]));
end

nVar_wb = mean(nVar_all);
ri_max  = min(nRxAntennas, 4);

% Broadcast H_wb to [K x L x nRx x nTx] for nrPMIReport / nrCQISelect
carrier.NSlot = 0;
nSC  = carrier.NSizeGrid * 12;
nSym = carrier.SymbolsPerSlot;
H_4d = repmat(reshape(H_wb, 1, 1, nRxAntennas, nTxAntennas), [nSC nSym 1 1]);

% ── Shared reportConfig struct for nrCQISelect (Rel-19) ──────────────────
repCfgCQI.NSizeBWP        = carrier.NSizeGrid;
repCfgCQI.NStartBWP       = 0;
repCfgCQI.CodebookType    = 'typeI-SinglePanel-r19';
repCfgCQI.PanelDimensions = [1, 16, 4];    % Ng=1, N1=16, N2=4 → 128 ports
repCfgCQI.PMIMode         = 'Wideband';
repCfgCQI.CQIMode         = 'Wideband';
repCfgCQI.CQITable        = 'table1';

% =========================================================================
%  APPROACH B: Full 128-Port SVD Upper Bound
% =========================================================================
[~, S_B, V_B]    = svd(H_wb, 'econ');
singVals_B       = diag(S_B);
snr_sv_B         = singVals_B.^2 / nVar_wb;
riThresh_B       = 0.1 * singVals_B(1);
ri_B             = min(sum(singVals_B > riThresh_B), nRxAntennas);
W_B              = V_B(:, 1:ri_B);

H_eff_B = H_wb * W_B;
W_zf_B  = pinv(H_eff_B);
sinr_B  = zeros(ri_B, 1);
for lyr = 1:ri_B
    sig  = abs(W_zf_B(lyr,:) * H_eff_B(:,lyr))^2;
    intf = sum(abs(W_zf_B(lyr,:) * H_eff_B).^2) - sig;
    nse  = nVar_wb * norm(W_zf_B(lyr,:))^2;
    sinr_B(lyr) = sig / (intf + nse);
end

% CQI via L2SM: build per-RE SINR matrix [nRE x ri_B] from wideband SINR
% (SVD has no codebook grid → replicate wideband SINR across all CSI-RS REs)
sinrPerRE_B = repmat(sinr_B(:).', nSC, 1);   % [nSC x ri_B], linear

repCfgCQI_B        = repCfgCQI;
repCfgCQI_B.CodebookType  = 'Type1SinglePanel';   % B uses SVD, not Rel-19 CB
repCfgCQI_B.PanelDimensions = [8, 2];             % dummy, CQI only needs SINR
[cqi_B_vec, ~] = nr5g.internal.nrCQISelect( ...
    carrier, csirs{1}, repCfgCQI_B, ri_B, H_4d, nVar_wb);
cqi_B = cqi_B_vec(1);   % wideband CQI (row 1)

cap_B = sum(log2(1 + snr_sv_B(1:ri_B) / ri_B));

fb.ri_B        = ri_B;
fb.cqi_B       = cqi_B;
fb.cap_B       = cap_B;
fb.W_B         = W_B;
fb.sinrPerRE_B = sinrPerRE_B;

% =========================================================================
%  APPROACH C: Rel-19 Mode A  — RI selection + CQI via nrCQISelect
% =========================================================================
repCfgCQI_C             = repCfgCQI;
repCfgCQI_C.CodebookMode = 1;

ri_C = 1;  best_rate_C = -Inf;
for ri_try = 1:ri_max
    try
        [~, info_try] = nr5g.internal.nrPMIReport( ...
            carrier, csirs{1}, ...
            setfield(nrCSIReportConfig, 'NSizeBWP', carrier.NSizeGrid, ...
                'NStartBWP', 0, 'CodebookType', 'typeI-SinglePanel-r19', ...
                'PanelDimensions', [1,16,4], 'PMIFormatIndicator', 'wideband', ...
                'CodebookMode', 1), ...
            ri_try, H_4d, nVar_wb);
        rate_ = real(log2(det(eye(nRxAntennas) + ...
            (1/nVar_wb) * (H_wb*info_try.W*(H_wb*info_try.W)'))));
        if rate_ > best_rate_C;  best_rate_C = rate_;  ri_C = ri_try;  end
    catch
    end
end

[cqi_C_vec, ~, ~, pmiInfo_C] = nr5g.internal.nrCQISelect( ...
    carrier, csirs{1}, repCfgCQI_C, ri_C, H_4d, nVar_wb);
cqi_C = cqi_C_vec(1);
W_C   = pmiInfo_C.W;
cap_C = real(log2(det(eye(nRxAntennas) + ...
    (1/nVar_wb) * (H_wb*W_C*(H_wb*W_C)'))));

fb.ri_C        = ri_C;
fb.cqi_C       = cqi_C;
fb.cap_C       = cap_C;
fb.W_C         = W_C;
fb.sinrPerRE_C = pmiInfo_C.SINRPerREPMI;

% =========================================================================
%  APPROACH D: Rel-19 Mode B  — RI selection + CQI via nrCQISelect
% =========================================================================
repCfgCQI_D             = repCfgCQI;
repCfgCQI_D.CodebookMode = 2;

ri_D = 1;  best_rate_D = -Inf;
for ri_try = 1:ri_max
    try
        [~, info_try] = nr5g.internal.nrPMIReport( ...
            carrier, csirs{1}, ...
            setfield(nrCSIReportConfig, 'NSizeBWP', carrier.NSizeGrid, ...
                'NStartBWP', 0, 'CodebookType', 'typeI-SinglePanel-r19', ...
                'PanelDimensions', [1,16,4], 'PMIFormatIndicator', 'wideband', ...
                'CodebookMode', 2), ...
            ri_try, H_4d, nVar_wb);
        rate_ = real(log2(det(eye(nRxAntennas) + ...
            (1/nVar_wb) * (H_wb*info_try.W*(H_wb*info_try.W)'))));
        if rate_ > best_rate_D;  best_rate_D = rate_;  ri_D = ri_try;  end
    catch
    end
end

[cqi_D_vec, ~, ~, pmiInfo_D] = nr5g.internal.nrCQISelect( ...
    carrier, csirs{1}, repCfgCQI_D, ri_D, H_4d, nVar_wb);
cqi_D = cqi_D_vec(1);
W_D   = pmiInfo_D.W;
cap_D = real(log2(det(eye(nRxAntennas) + ...
    (1/nVar_wb) * (H_wb*W_D*(H_wb*W_D)'))));

fb.ri_D        = ri_D;
fb.cqi_D       = cqi_D;
fb.cap_D       = cap_D;
fb.W_D         = W_D;
fb.sinrPerRE_D = pmiInfo_D.SINRPerREPMI;

end

