repCfg.NSizeBWP           = carrier.NSizeGrid;
repCfg.NStartBWP          = 0;
repCfg.CodebookType       = 'typeI-SinglePanel-r19';
repCfg.PanelDimensions    = [1, 16, 4];
repCfg.PMIFormatIndicator = 'wideband';
repCfg.CodebookMode       = 1;

ri_C = 1;  best_rate_C = -Inf;
