cqi_C     = arrayfun(@(s) max(sum(s >= cqi_tbl), 1), sinr_C_dB);

fb.ri_C  = ri_C;
fb.cqi_C = cqi_C;    % [1 x ri_C]
fb.cap_C = cap_C;
fb.W_C   = W_C;

