function m = csirs_computeMetrics(fb, carrier)
%CSIRS_COMPUTEMETRICS  Derive RI, MCS, Throughput from CSI feedback struct.
%
%  MCS is computed via nr5g.internal.computeMCS which uses L2SM internally,
%  giving the proper MCS index (0-28) per TS 38.214 Table 5.1.3.1-1 (qam64).
%
%  Throughput approximation (link-level, per slot):
%    TP = RI × ModOrder × CodeRate × N_RE_per_slot / T_slot
%
%  Inputs:
%    fb      - struct from csirs_feedback:
%                ri_B/C/D, cqi_B/C/D, cap_B/C/D
%                sinrPerRE_C, sinrPerRE_D  (linear, [nRE x nLayers])
%    carrier - nrCarrierConfig (NSizeGrid, SubcarrierSpacing)
%
%  Output:
%    m - struct (each field is [1x3] vector, order: B C D):
%          .ri  - RI per approach
%          .mcs - MCS index per approach (0-based, TS 38.214 Table 5.1.3.1-1)
%          .tp  - throughput in Mbps per approach

% ── Resource geometry ────────────────────────────────────────────────────
nPRB       = carrier.NSizeGrid;
nSym_PDSCH = 12;              % ~12 DMRS-free PDSCH symbols per slot
slotDur_s  = 1e-3 / (carrier.SubcarrierSpacing / 15);   % 0.5ms @ SCS 30kHz
nRE_slot   = nPRB * 12 * nSym_PDSCH;

% ── CSI reference resource (needed by computeMCS) ────────────────────────
% Build a minimal reportConfig and nrPDSCHConfig via nrCSIReferenceResource.
% Use the same BWP as carrier. CodebookType 'Type1SinglePanel' is a placeholder
% — computeMCS only uses carrier + pdsch for TBS/overhead, not codebook.
refCfg.NSizeBWP     = carrier.NSizeGrid;
refCfg.NStartBWP    = 0;
refCfg.CodebookType = 'Type1SinglePanel';
refCfg.CQITable     = 'table1';
refCfg.CQIMode      = 'Wideband';
refCfg.PMIMode      = 'Wideband';

l2sm = nr5g.internal.L2SM.initialize(carrier);

% ── MCS via computeMCS for each approach ─────────────────────────────────
%  computeMCS(l2smSRS, carrier, pdsch, sinr_linear, mcsTable)
%  sinr: [nRE x nLayers] linear SINR at CSI-RS locations

% Approach B: replicate wideband ZF SINR across nRE (no per-RE variation)
% sinrPerRE_B was stored in fb; if absent, derive from cqi_B via fallback
if isfield(fb, 'sinrPerRE_B')
    sinr_B = fb.sinrPerRE_B;
else
    sinr_B = db2pow(fb.cqi_B) * ones(nPRB*12, fb.ri_B);  % fallback
end
[pdsch_B, ~] = nrCSIReferenceResource(carrier, refCfg, fb.ri_B);
mcs_B = nr5g.internal.computeMCS(l2sm, carrier, pdsch_B, sinr_B, 'qam64');

% Approach C
[pdsch_C, ~] = nrCSIReferenceResource(carrier, refCfg, fb.ri_C);
mcs_C = nr5g.internal.computeMCS(l2sm, carrier, pdsch_C, fb.sinrPerRE_C, 'qam64');

% Approach D
[pdsch_D, ~] = nrCSIReferenceResource(carrier, refCfg, fb.ri_D);
mcs_D = nr5g.internal.computeMCS(l2sm, carrier, pdsch_D, fb.sinrPerRE_D, 'qam64');

% ── Throughput from MCS index (TS 38.214 Table 5.1.3.1-1, qam64) ─────────
mcsTableObj = nrPDSCHMCSTables;
mcsTab = mcsTableObj.QAM64Table;   % MCS index 0-28: [MCSIndex, Qm, TargetCodeRate, SE]

tp_fn = @(ri, mcsIdx) computeTP(ri, mcsIdx, mcsTab, nRE_slot, slotDur_s);

tp_B = tp_fn(fb.ri_B, mcs_B) / 1e6;   % Mbps
tp_C = tp_fn(fb.ri_C, mcs_C) / 1e6;
tp_D = tp_fn(fb.ri_D, mcs_D) / 1e6;

% ── Pack output ───────────────────────────────────────────────────────────
m.ri  = [fb.ri_B, fb.ri_C, fb.ri_D];
m.mcs = [mcs_B,   mcs_C,   mcs_D];
m.tp  = [tp_B,    tp_C,    tp_D];

end

% ── Helper: TP from MCS index ─────────────────────────────────────────────
function tp = computeTP(ri, mcsIdx, mcsTab, nRE_slot, slotDur_s)
    % mcsIdx is 0-based; mcsTab rows indexed from 1 in MATLAB
    row = mcsIdx + 1;
    if row < 1 || row > height(mcsTab) || isnan(mcsTab.TargetCodeRate(row))
        tp = 0;
        return;
    end
    modOrder = mcsTab.Qm(row);
    codeRate = mcsTab.TargetCodeRate(row);   % already in [0,1]
    tp = ri * modOrder * codeRate * nRE_slot / slotDur_s;
end

