function fb = csirs_feedback(carrier, csirs, H_est_full, nVar_all, slotAssign)
%CSIRS_FEEDBACK  CSI feedback (RI/PMI/CQI/Cap) for Approaches B, C, D.
%
%  Approach B: Full 128-port SVD upper bound (ideal reference)
%  Approach C: Rel-19 Type I Single-Panel Mode A (TS 38.214 S5.2.2.2.1a)
%  Approach D: Rel-19 Type I Single-Panel Mode B (TS 38.214 S5.2.2.2.1a)
%
%  CQI for C/D: computed via nr5g.internal.nrCQISelect (L2SM/MIESM,
%  BLER threshold 10%, per TS 38.214 S5.2.2.1) — now supports Rel-19.
%
%  Inputs:
%    carrier      - nrCarrierConfig
%    csirs        - {1x4} nrCSIRSConfig objects (csirs{1} used for C/D)
%    H_est_full   - [K x 28 x nRx x 128] estimated channel
%    nVar_all     - [1x4] noise variance per resource
%    slotAssign   - [1x4] slot index per resource
%
%  Output:
%    fb - struct:
%           .ri_B,  .cqi_B,  .cap_B,  .W_B
%           .ri_C,  .cqi_C,  .cap_C,  .W_C,  .sinrPerRE_C
%           .ri_D,  .cqi_D,  .cap_D,  .W_D,  .sinrPerRE_D
%         cqi_* is wideband scalar; cap_* is scalar (bits/s/Hz)

nRxAntennas  = size(H_est_full, 3);
nTxAntennas  = size(H_est_full, 4);
nPortsPerRes = nTxAntennas / 4;
nSymPerSlot  = carrier.SymbolsPerSlot;

% ── Wideband channel matrix H_wb [nRx x nTx] ─────────────────────────────
H_wb = zeros(nRxAntennas, nTxAntennas);
for r = 1:4
    pS = (r-1)*nPortsPerRes + 1;  pE = r*nPortsPerRes;
    sS = slotAssign(r)*nSymPerSlot + 1;
    sE = (slotAssign(r)+1)*nSymPerSlot;
    H_wb(:, pS:pE) = squeeze(mean(H_est_full(:, sS:sE, :, pS:pE), [1 2]));
end

nVar_wb = mean(nVar_all);
ri_max  = min(nRxAntennas, 4);

% Broadcast H_wb to [K x L x nRx x nTx] for nrPMIReport / nrCQISelect
carrier.NSlot = 0;
nSC = carrier.NSizeGrid * 12;
H_4d = repmat(reshape(H_wb, 1, 1, nRxAntennas, nTxAntennas), ...
              [nSC, carrier.SymbolsPerSlot, 1, 1]);

% ── Shared nrCSIReportConfig for Rel-19 ──────────────────────────────────
r19cfg_A                    = nrCSIReportConfig;
r19cfg_A.NSizeBWP           = carrier.NSizeGrid;
r19cfg_A.NStartBWP          = 0;
r19cfg_A.CodebookType       = 'typeI-SinglePanel-r19';
r19cfg_A.PanelDimensions    = [1, 16, 4];   % Ng=1, N1=16, N2=4 → 128 ports
r19cfg_A.PMIFormatIndicator = 'wideband';
r19cfg_A.CodebookMode       = 1;

r19cfg_B                    = r19cfg_A;
r19cfg_B.CodebookMode       = 2;

% ── Shared struct for nrCQISelect (Rel-19, now supported) ────────────────
cqiCfg.NSizeBWP        = carrier.NSizeGrid;
cqiCfg.NStartBWP       = 0;
cqiCfg.CodebookType    = 'typeI-SinglePanel-r19';
cqiCfg.PanelDimensions = [1, 16, 4];
cqiCfg.PMIMode         = 'Wideband';
cqiCfg.CQIMode         = 'Wideband';
cqiCfg.CQITable        = 'table1';

% =========================================================================
%  APPROACH B: Full 128-Port SVD Upper Bound
%  CQI: ZF SINR per layer → threshold table (wideband SVD, no codebook grid)
% =========================================================================
[~, S_B, V_B]    = svd(H_wb, 'econ');
singVals_B       = diag(S_B);
snr_sv_B         = singVals_B.^2 / nVar_wb;
riThresh_B       = 0.1 * singVals_B(1);
ri_B             = min(sum(singVals_B > riThresh_B), nRxAntennas);
W_B              = V_B(:, 1:ri_B);

H_eff_B = H_wb * W_B;
W_zf_B  = pinv(H_eff_B);
sinr_B  = zeros(ri_B, 1);
for lyr = 1:ri_B
    sig  = abs(W_zf_B(lyr,:) * H_eff_B(:,lyr))^2;
    intf = sum(abs(W_zf_B(lyr,:) * H_eff_B).^2) - sig;
    nse  = nVar_wb * norm(W_zf_B(lyr,:))^2;
    sinr_B(lyr) = sig / (intf + nse);
end
cqi_tbl = [-6.7,-4.7,-2.3,0.2,2.4,4.7,6.9,9.3,10.7,12.2,14.1,15.6,18.0,20.3,22.7];
sinr_B_dB = 10*log10(sinr_B);
cqi_B     = max(sum(mean(sinr_B_dB) >= cqi_tbl), 1);   % wideband scalar
cap_B     = sum(log2(1 + snr_sv_B(1:ri_B) / ri_B));

fb.ri_B  = ri_B;
fb.cqi_B = cqi_B;
fb.cap_B = cap_B;
fb.W_B   = W_B;

% =========================================================================
%  APPROACH C: Rel-19 Mode A
%  RI: capacity-based selection via nrPMIReport
%  CQI: nrCQISelect (L2SM/MIESM) — now supports typeI-SinglePanel-r19
% =========================================================================
ri_C = 1;  best_rate_C = -Inf;
for ri_try = 1:ri_max
    try
        [~, info_try] = nr5g.internal.nrPMIReport( ...
            carrier, csirs{1}, r19cfg_A, ri_try, H_4d, nVar_wb);
        rate_ = real(log2(det(eye(nRxAntennas) + ...
            (1/nVar_wb) * (H_wb*info_try.W*(H_wb*info_try.W)'))));
        if rate_ > best_rate_C;  best_rate_C = rate_;  ri_C = ri_try;  end
    catch
    end
end

cqiCfg_C             = cqiCfg;
cqiCfg_C.CodebookMode = 1;
[cqi_C_vec, ~, ~, pmiInfo_C] = nr5g.internal.nrCQISelect( ...
    carrier, csirs{1}, cqiCfg_C, ri_C, H_4d, nVar_wb);
cqi_C = cqi_C_vec(1);   % wideband CQI (row 1 = wideband)
W_C   = pmiInfo_C.W;
cap_C = real(log2(det(eye(nRxAntennas) + ...
    (1/nVar_wb) * (H_wb*W_C*(H_wb*W_C)'))));

fb.ri_C        = ri_C;
fb.cqi_C       = cqi_C;
fb.cap_C       = cap_C;
fb.W_C         = W_C;
fb.sinrPerRE_C = pmiInfo_C.SINRPerREPMI;

% =========================================================================
%  APPROACH D: Rel-19 Mode B
%  RI: capacity-based selection via nrPMIReport
%  CQI: nrCQISelect (L2SM/MIESM) — typeI-SinglePanel-r19
% =========================================================================
ri_D = 1;  best_rate_D = -Inf;
for ri_try = 1:ri_max
    try
        [~, info_try] = nr5g.internal.nrPMIReport( ...
            carrier, csirs{1}, r19cfg_B, ri_try, H_4d, nVar_wb);
        rate_ = real(log2(det(eye(nRxAntennas) + ...
            (1/nVar_wb) * (H_wb*info_try.W*(H_wb*info_try.W)'))));
        if rate_ > best_rate_D;  best_rate_D = rate_;  ri_D = ri_try;  end
    catch
    end
end

cqiCfg_D             = cqiCfg;
cqiCfg_D.CodebookMode = 2;
[cqi_D_vec, ~, ~, pmiInfo_D] = nr5g.internal.nrCQISelect( ...
    carrier, csirs{1}, cqiCfg_D, ri_D, H_4d, nVar_wb);
cqi_D = cqi_D_vec(1);
W_D   = pmiInfo_D.W;
cap_D = real(log2(det(eye(nRxAntennas) + ...
    (1/nVar_wb) * (H_wb*W_D*(H_wb*W_D)'))));

fb.ri_D        = ri_D;
fb.cqi_D       = cqi_D;
fb.cap_D       = cap_D;
fb.W_D         = W_D;
fb.sinrPerRE_D = pmiInfo_D.SINRPerREPMI;

end

function m = csirs_computeMetrics(fb, carrier)
%CSIRS_COMPUTEMETRICS  Derive RI, MCS, Throughput from CSI feedback struct.
%
%  MCS is computed via nr5g.internal.computeMCS (L2SM/MIESM internally),
%  giving the proper MCS index (0-based) per TS 38.214 Table 5.1.3.1-1 (qam64).
%
%  Throughput approximation (link-level, per slot):
%    TP = RI x ModOrder x CodeRate x N_RE_per_slot / T_slot
%
%  Inputs:
%    fb      - struct from csirs_feedback:
%                ri_B/C/D, cqi_B/C/D, cap_B/C/D
%                sinrPerRE_C, sinrPerRE_D  (linear [nRE x nLayers])
%    carrier - nrCarrierConfig (NSizeGrid, SubcarrierSpacing)
%
%  Output:
%    m - struct (each field is [1x3] vector, order: B C D):
%          .ri  - RI per approach
%          .mcs - MCS index per approach (0-based, TS 38.214 Table 5.1.3.1-1)
%          .tp  - throughput in Mbps per approach

% ── Resource geometry ────────────────────────────────────────────────────
nPRB       = carrier.NSizeGrid;
nSym_PDSCH = 12;            % ~12 DMRS-free PDSCH symbols per slot
slotDur_s  = 1e-3 / (carrier.SubcarrierSpacing / 15);   % 0.5ms @ SCS 30kHz
nRE_slot   = nPRB * 12 * nSym_PDSCH;

% ── L2SM init ────────────────────────────────────────────────────────────
l2sm = nr5g.internal.L2SM.initialize(carrier);

% ── MCS via computeMCS for each approach ─────────────────────────────────
%  computeMCS(l2smSRS, carrier, pdsch, sinr_linear [nRE x nLayers], mcsTable)
%  nrPDSCHConfig is built manually (nrCSIReferenceResource not in local lib).

% Approach B: replicate wideband ZF SINR to [nRE x ri_B]
sinr_B = repmat(db2pow(mean(10*log10(fb.sinrPerRE_B))), nPRB*12, 1);
pdsch_B = makePDSCH(carrier, fb.ri_B);
mcs_B = nr5g.internal.computeMCS(l2sm, carrier, pdsch_B, sinr_B, 'qam64');

% Approach C
pdsch_C = makePDSCH(carrier, fb.ri_C);
mcs_C = nr5g.internal.computeMCS(l2sm, carrier, pdsch_C, fb.sinrPerRE_C, 'qam64');

% Approach D
pdsch_D = makePDSCH(carrier, fb.ri_D);
mcs_D = nr5g.internal.computeMCS(l2sm, carrier, pdsch_D, fb.sinrPerRE_D, 'qam64');

% ── Throughput from MCS index (TS 38.214 Table 5.1.3.1-1, qam64) ─────────
mcsTab = nrPDSCHMCSTables().QAM64Table;   % columns: MCSIndex Qm TargetCodeRate SE

tp_fn = @(ri, mcsIdx) computeTP(ri, mcsIdx, mcsTab, nRE_slot, slotDur_s);

tp_B = tp_fn(fb.ri_B, mcs_B) / 1e6;   % Mbps
tp_C = tp_fn(fb.ri_C, mcs_C) / 1e6;
tp_D = tp_fn(fb.ri_D, mcs_D) / 1e6;

% ── Pack output ───────────────────────────────────────────────────────────
m.ri  = [fb.ri_B, fb.ri_C, fb.ri_D];
m.mcs = [mcs_B,   mcs_C,   mcs_D];
m.tp  = [tp_B,    tp_C,    tp_D];

end

% ── Helper: build minimal nrPDSCHConfig for CSI reference resource ────────
function pdsch = makePDSCH(carrier, nLayers)
    pdsch            = nrPDSCHConfig;
    pdsch.PRBSet     = 0:carrier.NSizeGrid-1;
    pdsch.NumLayers  = nLayers;
    pdsch.MCSTable   = 'qam64';
end

% ── Helper: TP from MCS index ─────────────────────────────────────────────
function tp = computeTP(ri, mcsIdx, mcsTab, nRE_slot, slotDur_s)
    row = mcsIdx + 1;   % mcsIdx is 0-based; MATLAB table is 1-based
    if row < 1 || row > height(mcsTab) || isnan(mcsTab.TargetCodeRate(row))
        tp = 0;
        return;
    end
    modOrder = mcsTab.Qm(row);
    codeRate = mcsTab.TargetCodeRate(row);   % in [0,1]
    tp = ri * modOrder * codeRate * nRE_slot / slotDur_s;
end

